sp_widget.link:
function(scope, elem) {
	$(elem).on('keydown','.header-menu-item',function(e){
		var target = e.target;
		if (target.localName == 'a') {
			var currentMenuItem = $(target).parents('li');
			var parentUL = currentMenuItem.parents('ul');
			var allMenuItems = parentUL.children('li:visible');
			var firstMenuItem = allMenuItems.first();
			var lastMenuItem = allMenuItems.last();
			var menuItemToFocus;
			if(e.keyCode == 37) {
				e.preventDefault();
				currentMenuItem.removeClass('open');
				var previousMenuItem = currentMenuItem.prevAll('li:visible').first();
				//enable circular navigation
				menuItemToFocus = previousMenuItem.length ? previousMenuItem : lastMenuItem;
				menuItemToFocus.find('a').focus();
			} else if(e.keyCode == 39) {
				e.preventDefault();
				currentMenuItem.removeClass('open');
				var nextMenuItem = currentMenuItem.nextAll('li:visible').first();
				//enable circular navigation
				menuItemToFocus = nextMenuItem.length ? nextMenuItem : firstMenuItem;
				menuItemToFocus.find('a').focus();
			}
			if(e.keyCode == 9) {
				$(target).parents('li').removeClass('open');
			}
		}
		});
	}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
/* Special License Rights
*  The Government's rights to use, display, or disclose this software are restricted.
*  Any reproduction of computer software, computer software documentation,
*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: ROBERT JOY
// WIDGET BASE: HEADER MENU
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 2021-11-01 | raj | STRY0114307 - 1. Artifact Story: Tasker Portal Page- Navigation Bar- New icons update
//                                         Changes made in tasker-menuTemplate and Server Script
// 2.7.2 | 2021-01-27 | raj | DFCT0010774 - New Menu Items with Glyph do not align with drop down menu items with the Discover SVG
//                                         Changes made in tasker-menuTemplate
// 2.8   | 2021-04-14 | raj | STRY0117600 - Update Templates to match the UI of Org Hierarchy 
//                                         Changes made in Server Only removed the Org Hierarchy hard coded values as it is built in script now
// 2.8   | 2022-04-27 | raj | STRY0120910 - Layout Selector (Org Hierarchy)- Add Fullscreen Tree as an option
//                                         Changes made in tasker_menuTemplate - added a check for condition on each item
// 2.8   | 2022-05-15 | raj | STRY0118963 - Homepage to Org Hierarchy- System remembers user in Bifold/Fullscreen/Table/List
//                                         Changes made in Server Script
// 
//------------------------------------------------------------------------------------------------------------------------
(function($sp, input, data, options, gs) {
	// STRY0118963 - updated to follow our standard format
	main();

	function main(){
		// build menus
		var menu_id = $sp.getValue('sys_id'); // instance sys_id
		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('tasker-header-menu');
		if(input){
			// if the filter changed, save it back
			if(input.pageChanged){
				taskWidgetIconsAndMessage.savePreferenceUserDefaultLandingPage(input.newPage);
			}
		}
		data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);
		data.messages = taskWidgetIconsAndMessage.loadMessages();
		data.icons = taskWidgetIconsAndMessage.loadIcons();


		// STRY0114307 - need sys_id for links
		data.sys_id = $sp.getParameter("sys_id");

		getMenuItems(menu_id);

		// STRY0114307
		setItemSrcOnAllDescendants(data.menu.items);

		data.isLoggedIn = GlideSession.get().isLoggedIn();		
	}

	function getMenuItems(menu_id){
		data.menu = {};
		data.menu.items = $sp.getMenuItems(menu_id);		
	}

	function setItemSrcOnAllDescendants(items){
		// STRY0114307
		for (var i in items){
			var item = items[i];
			// STRY0118963 - change how this works to allow different URL to be loaded
			var itemLabel = item.label.toString();
			if(itemLabel.toLowerCase().substring(0,6) == 'dtech-'){
				// using the SVG name in the menu item allows us to remove hard coding
				// we can use the svg name to set the svg
				var svgName = itemLabel.substring(6);
				// we can also use svg name to get the title from a message
				var icon = data.icons[svgName];
				item.src = icon.src;
				item.label = icon.title;
				// STRY0118963 - get the updated URL for org
				switch (icon.src){
					case "OrgHierarchy16.svg":
						if(data.settings.orgUserDefaultPageId){
							item.href = '?id=' + 
								data.settings.orgUserDefaultPageId + 
								'&table=x_153465_discovert_discover_office_hierarchy&spa=1&view=sp';
						}
						break;
					case "Divider_Black.svg":
						item.isDivider = true;
						break;
					case "Task24.svg":
						if(data.settings.userDefaultLandingPage == "my_task_home_page"){
							item.isSelectedPage = true;
						}
						break;
					case "Office24.svg":
						if(data.settings.userDefaultLandingPage == "my_ous_tasks_home_page"){
							item.isSelectedPage = true;
						}
						break;
				}
			}
			// if item has href and doesn't have sys_id in href, add the id
			if(item.href && item.href.indexOf("sys_id") == -1){
				item.href = item.href + "&sys_id=" + data.sys_id;
			}

			// if item has items recurse
			if(item.items && item.items.length > 0){
				setItemSrcOnAllDescendants(item.items);
			}
			// process the scripted items also
			if(item.scriptedItems && item.scriptedItems.items && item.scriptedItems.items.length > 0){
				setItemSrcOnAllDescendants(item.scriptedItems.items);
			}
		}

	}
})($sp, input, data, options, gs);
